import java.util.Arrays;

public class MergeSort {

    /**
     * This method sorts an array of non-negative integers using the Merge Sort algorithm.
     * It handles unexpected inputs by checking if the input array is null or contains negative values.
     *
     * @param arr the array of non-negative integers to be sorted
     */
    public static void sort(int[] arr) {
        // Check if the input array is null
        if (arr == null) {
            System.out.println("Error: Input array cannot be null.");
            return;
        }

        // Check for negative values in the array
        for (int value : arr) {
            if (value < 0) {
                System.out.println("Error: Array contains negative values.");
                return;
            }
